"""
NeonGrid-9 :: Kapitel 5 — PERMISSION MATRIX
LPIC-1 Topic 104.5 / 104.6 / 104.7
Dateirechte, Links & Dateisystem-Hierarchie

"In NeonGrid-9 entscheidet die Permission-Matrix
 wer lebt, wer liest und wer schreibt."
"""
from engine.mission_engine import Mission, QuizQuestion
CHAPTER_5_MISSIONS: list[Mission] = [Mission(mission_id='5.01', chapter=5, title='rwx — Die Permission Matrix lesen', mtype='DECODE', xp=50, speaker='ZARA Z3R0', story="Zara Z3R0 öffnet eine holografische Datei-Tabelle.\n'Jede Datei in NeonGrid-9 hat eine Permission-Matrix, Ghost.\n rwx. Neun Bits. Über Leben und Tod der Daten.\n Lies sie — oder bleib gesperrt.'", why_important='Dateirechte sind das Fundament der Linux-Sicherheit.\nLPIC-1 prüft das Lesen von ls -l Ausgaben, Oktalnotation\nund den Unterschied zwischen Datei- und Verzeichnisrechten.', explanation='Dateirechte — Drei Oktette:\n\n  $ ls -l /etc/passwd\n  -rw-r--r-- 1 root root 2456 Jan 15 08:00 /etc/passwd\n\nFormat: [Typ][Owner][Group][Other]\n  -       = normale Datei\n  d       = Verzeichnis\n  l       = Symlink\n\nBits:\n  r = read    (lesen)     = 4\n  w = write   (schreiben) = 2\n  x = execute (ausführen) = 1\n  - = kein Recht          = 0\n\nOktalnotation:\n  rwx = 4+2+1 = 7\n  rw- = 4+2+0 = 6\n  r-x = 4+0+1 = 5\n  r-- = 4+0+0 = 4\n  --- = 0+0+0 = 0\n\nBeispiele:\n  rwxr-xr-x = 755  (Owner: alles, Rest: lesen+ausführen)\n  rw-r--r-- = 644  (Owner: lesen+schreiben, Rest: nur lesen)\n  rw------- = 600  (nur Owner hat Zugriff)\n  rwx------ = 700  (nur Owner kann ausführen)\n\nVerzeichnis-Rechte:\n  r = Inhalt auflisten (ls)\n  w = Dateien erstellen/löschen\n  x = Verzeichnis betreten (cd)', ascii_art='\n  ██████╗ ███████╗██████╗ ███╗   ███╗███████╗     ██████╗ ██╗  ██╗███╗   ███╗██████╗\n  ██╔══██╗██╔════╝██╔══██╗████╗ ████║██╔════╝    ██╔═══██╗██║  ██║████╗ ████║██╔══██╗\n  ██████╔╝█████╗  ██████╔╝██╔████╔██║███████╗    ██║   ██║███████║██╔████╔██║██║  ██║\n  ██╔═══╝ ██╔══╝  ██╔══██╗██║╚██╔╝██║╚════██║    ██║   ██║██╔══██║██║╚██╔╝██║██║  ██║\n  ██║     ███████╗██║  ██║██║ ╚═╝ ██║███████║    ╚██████╔╝██║  ██║██║ ╚═╝ ██║██████╔╝\n  ╚═╝     ╚══════╝╚═╝  ╚═╝╚═╝     ╚═╝╚══════╝     ╚═════╝ ╚═╝  ╚═╝╚═╝     ╚═╝╚═════╝\n\n  [ CHAPTER 05 :: PERMISSIONS & ACCESS ]\n  > rwxr-xr-x... Access matrix loading. Who controls the files?', story_transitions=['Zara zeigt dir die Zugriffsmatrix. r=4 w=2 x=1.', 'Wer besitzt die Datei? Wer darf sie lesen? Wer ausführen?', 'chmod, chown, umask — die Werkzeuge der Kontrolle.', 'Falsche Berechtigungen öffnen Backdoors. Kenn dein rwx.'], syntax='ls -l /etc/passwd\nls -la ~', example='$ ls -la /home/ghost\ndrwxr-xr-x  2 ghost ghost 4096 Jan 15 08:00 .\ndrwxr-xr-x 10 root  root  4096 Jan 15 07:00 ..\n-rw-r--r--  1 ghost ghost  220 Jan 15 07:00 .bash_logout\n-rwxr-xr-x  1 ghost ghost 8192 Jan 15 08:00 scan.sh', task_description='Zeige Dateien mit Berechtigungen in /etc', expected_commands=['ls -l', 'ls -la'], hints=["Ein Auflistungsbefehl wie 'ls' wird benötigt.", 'Versuche: ls -l', 'Der vollständige Befehl: ls -l'], hint_text='ls -l zeigt Dateirechte im rwx-Format', quiz_questions=[QuizQuestion(question="Was ist die Oktalnotation für 'rw-r--r--'?", options=['A) 755', 'B) 644', 'C) 600', 'D) 664'], correct='B', explanation='rw- = 6, r-- = 4, r-- = 4. Ergibt 644.', xp_value=20), QuizQuestion(question="Was bedeutet 'x' bei einem VERZEICHNIS?", options=['A) Das Verzeichnis ist ausführbar', 'B) Man kann das Verzeichnis betreten (cd)', 'C) Scripts im Verzeichnis können ausgeführt werden', 'D) Das Verzeichnis ist verschlüsselt'], correct='B', explanation='x bei Verzeichnissen = Betreten erlaubt (cd, Dateien öffnen). Ohne x kann man nicht hinein, auch wenn r gesetzt ist.', xp_value=20)], exam_tip='Oktal merken: r=4, w=2, x=1. Addieren.\n755 = rwxr-xr-x (Programmdateien)\n644 = rw-r--r-- (normale Dateien)\n700 = rwx------ (private Skripte)', memory_tip='r=4, w=2, x=1. 755=Programme, 644=Dateien, 700=privat.', gear_reward=None, faction_reward=('Root Collective', 3)), Mission(mission_id='5.02', chapter=5, title='chmod — Die Permission Matrix reprogrammieren', mtype='INFILTRATE', xp=85, speaker='ZARA Z3R0', story="Ghost findet eine gesperrte Datei: '-r--------'\nZara Z3R0: 'chmod ist dein Schlüssel zur Matrix.\n Oktal oder symbolisch — beide Wege führen zum Ziel.'", why_important='chmod ist einer der häufigsten Linux-Befehle.\nLPIC-1 prüft BEIDE Varianten: Oktal und symbolisch.', explanation='chmod — Change Mode:\n\nOktal-Notation:\n  chmod 755 skript.sh    # rwxr-xr-x\n  chmod 644 config.txt   # rw-r--r--\n  chmod 600 .ssh/id_rsa  # rw-------\n  chmod 777 /tmp/share   # rwxrwxrwx (gefährlich!)\n  chmod -R 755 /var/www  # rekursiv\n\nSymbolische Notation:\n  u = user (owner)\n  g = group\n  o = other\n  a = all (u+g+o)\n\n  + = hinzufügen\n  - = entfernen\n  = = setzen (genau)\n\nBeispiele symbolisch:\n  chmod u+x skript.sh        # Owner: execute hinzufügen\n  chmod go-w datei.txt       # Group+Other: write entfernen\n  chmod a+r datei.txt        # alle: read\n  chmod u=rwx,go=rx prog     # exakt setzen\n  chmod +x skript.sh         # alle: execute\n  chmod -x skript.sh         # alle: execute entfernen\n\nRekursiv:\n  chmod -R 755 /var/www/html', syntax='chmod 755 datei\nchmod u+x datei\nchmod -R 644 verzeichnis/', example='$ chmod 755 /usr/local/bin/neongrid\n$ chmod u+x,go-w skript.sh\n$ chmod -R 644 /etc/nginx/conf.d/', task_description='Zeige Dateien mit Berechtigungen', expected_commands=['ls -l', 'ls -la'], hints=["Ein Auflistungsbefehl wie 'ls' wird benötigt.", 'Versuche: ls -l', 'Der vollständige Befehl: ls -l'], hint_text='ls -l zeigt die aktuellen Rechte nach chmod', quiz_questions=[QuizQuestion(question='Welcher Befehl gibt dem Owner Execute-Rechte, ohne andere Rechte zu ändern?', options=['A) chmod 100 datei', 'B) chmod u+x datei', 'C) chmod +100 datei', 'D) chmod o-x datei'], correct='B', explanation='chmod u+x = user (owner) + execute hinzufügen. Andere Bits unverändert.', xp_value=25), QuizQuestion(question='chmod go= datei — was passiert?', options=['A) Group und Other: alle Rechte entfernen', 'B) Group und Other: alle Rechte setzen', 'C) Fehler — ungültige Syntax', 'D) Group und Other: execute setzen'], correct='A', explanation='go= ohne Buchstaben = leere Menge = alle Rechte von group und other entfernen.', xp_value=25)], exam_tip='chmod 755 = häufigster Wert für ausführbare Dateien.\nchmod 644 = häufigster Wert für Konfigurationsdateien.\nSymbolisch: u=owner, g=group, o=other, a=all.\n+/-/= für hinzufügen/entfernen/setzen.', memory_tip='chmod u+x = user+execute. chmod go-w = group+other minus write.', gear_reward=None, faction_reward=('Root Collective', 4)), Mission(mission_id='5.03', chapter=5, title='chown & chgrp — Besitz übertragen', mtype='INFILTRATE', xp=80, speaker='RUST', story="Ghost hat eine Datei von einem anderen Hacker übernommen.\nSie gehört noch dem alten Owner.\nRust: 'chown macht sie zu deiner Datei. Nimm was dir gehört.'", why_important='chown und chgrp sind essentiell für System-Administration.\nLPIC-1 prüft Syntax und die kombinierte Schreibweise owner:group.', explanation="chown — Change Owner:\n\n  chown ghost datei.txt         # Owner zu 'ghost'\n  chown ghost:hackers datei.txt # Owner + Group\n  chown :hackers datei.txt      # nur Group\n  chown -R ghost /home/ghost    # rekursiv\n\nchgrp — Change Group:\n\n  chgrp hackers datei.txt       # Group zu 'hackers'\n  chgrp -R www-data /var/www    # rekursiv\n\nBesitzer anzeigen:\n  ls -l datei.txt\n  stat datei.txt               # detailliert\n\nBenutzer und Gruppen anzeigen:\n  id                           # eigene UID/GID\n  id ghost                     # andere User\n  groups                       # eigene Gruppen\n  cat /etc/passwd              # alle User\n  cat /etc/group               # alle Gruppen\n\nNur root darf chown nutzen (auf fremde Dateien)!", syntax='chown user:group datei\nchown -R www-data /var/www', example='$ chown ghost:hackers /opt/neongrid.py\n$ chgrp -R www-data /var/www/html\n$ ls -l /opt/neongrid.py\n-rwxr-xr-x 1 ghost hackers 4096 Jan 15 08:00 /opt/neongrid.py', task_description='Zeige Dateien mit Owner und Group', expected_commands=['ls -l', 'stat'], hints=["Ein Auflistungsbefehl wie 'ls' wird benötigt.", 'Versuche: ls -l', 'Der vollständige Befehl: ls -l'], hint_text='ls -l zeigt Owner und Group in Spalte 3 und 4', quiz_questions=[QuizQuestion(question="Was macht 'chown :gruppe datei' (nur Doppelpunkt + Gruppe)?", options=['A) Setzt Owner und Gruppe', 'B) Setzt nur die Gruppe', 'C) Fehler', 'D) Löscht den Owner'], correct='B', explanation='chown :gruppe = nur Gruppe setzen (wie chgrp). chown user:gruppe = beides.', xp_value=20), QuizQuestion(question='Welcher Befehl ändert Besitzer rekursiv für ein ganzes Verzeichnis?', options=['A) chown user /verz', 'B) chown -R user:group /verz', 'C) chgrp -r user /verz', 'D) chmod -R user /verz'], correct='B', explanation='chown -R = rekursiv. Ändert Owner und Gruppe aller Dateien im Verzeichnis.', xp_value=20)], exam_tip='chown user:group = Owner und Group gleichzeitig setzen.\nchown :group = nur Group (wie chgrp).\nchown -R = rekursiv für Verzeichnisse.\nNur root kann chown auf fremde Dateien anwenden.', memory_tip='chown user:group datei. Doppelpunkt trennt User und Group.', gear_reward=None, faction_reward=('Root Collective', 3)), Mission(mission_id='5.04', chapter=5, title='umask — Die Rechte-Schablone', mtype='DECODE', xp=85, speaker='ZARA Z3R0', story="Jede neue Datei in NeonGrid-9 bekommt automatisch Rechte.\nAber woher kommen diese Standardrechte?\nZara Z3R0: 'umask. Die unsichtbare Schablone, Ghost.'", why_important='umask bestimmt Standardrechte für neue Dateien und Verzeichnisse.\nLPIC-1 prüft umask-Berechnung intensiv — eine Lieblingsfrage!', explanation='umask — User File-Creation Mode Mask:\n\nFormel:\n  Neue Datei:       666 - umask = tatsächliche Rechte\n  Neues Verzeichnis: 777 - umask = tatsächliche Rechte\n\nStandard umask = 022:\n  Datei:       666 - 022 = 644  (rw-r--r--)\n  Verzeichnis: 777 - 022 = 755  (rwxr-xr-x)\n\numask = 027:\n  Datei:       666 - 027 = 640  (rw-r-----)\n  Verzeichnis: 777 - 027 = 750  (rwxr-x---)\n\numask = 077:\n  Datei:       666 - 077 = 600  (rw-------)\n  Verzeichnis: 777 - 077 = 700  (rwx------)\n\numask anzeigen und setzen:\n  umask          # aktuellen Wert anzeigen\n  umask 022      # setzen (für aktuelle Shell)\n  umask -S       # symbolisch anzeigen: u=rwx,g=rx,o=rx\n\nDauerhaft setzen:\n  In ~/.bashrc oder /etc/profile oder /etc/login.defs\n\nWICHTIG: Dateien bekommen KEIN execute durch umask!\n  Maximale Basis für Dateien ist 666 (kein x)', syntax='umask\numask 022\numask -S', example='$ umask\n0022\n$ umask -S\nu=rwx,g=rx,o=rx\n$ touch testfile && ls -l testfile\n-rw-r--r-- 1 ghost ghost 0 Jan 15 08:00 testfile', task_description='Zeige den aktuellen umask-Wert', expected_commands=['umask', 'umask -S'], hints=["Ein Auflistungsbefehl wie 'umask' wird benötigt.", 'Der Befehl selbst ist: umask', 'Der vollständige Befehl: umask'], hint_text='umask ohne Argumente zeigt den aktuellen Wert', quiz_questions=[QuizQuestion(question='umask ist 027. Welche Rechte hat eine neue Datei?', options=['A) 750', 'B) 640', 'C) 644', 'D) 777'], correct='B', explanation='Dateien: 666 - 027 = 640 (rw-r-----). Nicht 750 — das wäre ein Verzeichnis (777-027).', xp_value=25), QuizQuestion(question='Warum bekommen neue Dateien nie execute-Rechte durch den Standardmechanismus?', options=['A) Weil umask immer execute blockiert', 'B) Weil die Basis für Dateien 666 ist (kein x)', 'C) Weil nur root execute vergeben kann', 'D) Weil execute erst mit chmod gesetzt wird'], correct='B', explanation='Basis-Maximum für Dateien ist 666 (rw-rw-rw-). Execute-Bit fehlt — egal welche umask.', xp_value=25)], exam_tip='umask-Formel: Datei = 666 - umask, Verzeichnis = 777 - umask.\nStandard: 022 → Datei 644, Verzeichnis 755.\nDateien können KEIN x durch umask bekommen (Basis = 666).', memory_tip='umask SUBTRAHIERT von 666 (Datei) oder 777 (Verzeichnis). 022→644/755.', gear_reward=None, faction_reward=('Root Collective', 4)), Mission(mission_id='5.05', chapter=5, title='SUID / SGID / Sticky — Die Special Bits', mtype='DECODE', xp=100, speaker='ZARA Z3R0', story="Drei versteckte Bits in der Permission Matrix.\nSie geben Programme mehr Macht als erlaubt.\nZara Z3R0: 'SUID, SGID, Sticky Bit — die Waffen der Götter.\n Wer sie nicht kennt, wird sie nicht finden.'", why_important='Special Bits sind sicherheitskritisch und LPIC-1-Lieblingsstoff.\nSUID auf /etc/passwd erklärt warum gewöhnliche User ihr Passwort ändern können.', explanation="SUID — Set User ID:\n  - Programm läuft mit Owner-Rechten (meist root)\n  - ls -l zeigt 's' statt 'x' beim Owner\n  - Beispiel: /usr/bin/passwd (Benutzer ändert root-Datei)\n  - Oktal: 4xxx (z.B. 4755)\n  chmod u+s /usr/bin/myprog\n  chmod 4755 /usr/bin/myprog\n\nSGID — Set Group ID:\n  - Auf Datei: Programm läuft mit Gruppen-Rechten des Owners\n  - Auf Verzeichnis: Neue Dateien erben die Gruppe\n  - ls -l zeigt 's' statt 'x' bei Group\n  - Oktal: 2xxx (z.B. 2755)\n  chmod g+s /shared/dir\n  chmod 2755 /shared/dir\n\nSticky Bit:\n  - Auf Verzeichnis: Nur Owner darf eigene Dateien löschen\n  - Beispiel: /tmp (jeder schreibt, niemand löscht fremdes)\n  - ls -l zeigt 't' statt 'x' bei Other\n  - Oktal: 1xxx (z.B. 1777)\n  chmod +t /tmp\n  chmod 1777 /tmp\n\nErkennen in ls -l:\n  -rwsr-xr-x = SUID gesetzt (s bei Owner-x)\n  drwxrwsr-x = SGID gesetzt (s bei Group-x)\n  drwxrwxrwt = Sticky Bit (t bei Other-x)\n  GROSSES S/T = Bit gesetzt aber x fehlt (gefährlich!)\n\nSUID-Dateien finden:\n  find / -perm -4000 2>/dev/null   # SUID\n  find / -perm -2000 2>/dev/null   # SGID\n  find / -perm -1000 2>/dev/null   # Sticky", syntax='chmod u+s datei   # SUID\nchmod g+s dir     # SGID\nchmod +t /tmp     # Sticky', example="$ ls -l /usr/bin/passwd\n-rwsr-xr-x 1 root root 59976 Jan 15 2023 /usr/bin/passwd\n  ↑ 's' = SUID gesetzt!\n\n$ ls -ld /tmp\ndrwxrwxrwt 18 root root 4096 Jan 15 08:00 /tmp\n  ↑ 't' = Sticky Bit gesetzt!", task_description='Zeige Dateien mit SUID (ls -l /usr/bin/passwd)', expected_commands=['ls -l /usr/bin/passwd', 'ls -l'], hints=["Das Verzeichnis oder die Datei befinden sich unter '/usr/bin/passwd'. Der Befehl beginnt mit 'ls'.", 'Versuche: ls -l /usr/bin/passwd', 'Der vollständige Befehl: ls -l /usr/bin/passwd'], hint_text="ls -l /usr/bin/passwd zeigt SUID als 's' im rwx-String", quiz_questions=[QuizQuestion(question="Was bedeutet 's' an Position Owner-x in '-rwsr-xr-x'?", options=['A) Die Datei ist verschlüsselt', 'B) SUID ist gesetzt — Programm läuft mit Owner-Rechten', 'C) Die Datei gehört dem System', 'D) Sticky Bit ist gesetzt'], correct='B', explanation='s an Owner-x-Position = SUID. Das Programm läuft mit den Rechten des Owners (oft root).', xp_value=25), QuizQuestion(question='Warum hat /tmp das Sticky Bit?', options=['A) Damit Dateien in /tmp nicht gelöscht werden können', 'B) Damit jeder schreiben, aber nur der Owner eigene Dateien löschen kann', 'C) Damit /tmp schneller ist', 'D) Damit /tmp im RAM bleibt'], correct='B', explanation='Sticky Bit auf Verzeichnis: Löschen nur durch Datei-Owner oder root. Gut für gemeinsame Verzeichnisse.', xp_value=25)], exam_tip='SUID=4xxx (s bei owner-x), SGID=2xxx (s bei group-x), Sticky=1xxx (t bei other-x).\nGroßes S/T = Bit gesetzt aber execute fehlt.\nSUID finden: find / -perm -4000\n/tmp hat 1777 (rwxrwxrwt)', memory_tip='SUID=4=owner-s. SGID=2=group-s. Sticky=1=other-t. /tmp=1777.', gear_reward=None, faction_reward=('Root Collective', 5)), Mission(mission_id='5.06', chapter=5, title='Hard Links & Symlinks — Doppelgänger-Protokoll', mtype='CONSTRUCT', xp=90, speaker='RUST', story="Ghost will eine Datei an zwei Orten gleichzeitig haben.\nRust erklärt: 'Zwei Wege, Ghost. Hard Links und Symlinks.\n Beide verbinden. Aber ihr Tod ist verschieden.'", why_important='Links sind fundamental für Linux-Systemstruktur.\nLPIC-1 prüft den Unterschied: Hard Link = gleiche Inode, Symlink = Pfad-Zeiger.', explanation="Hard Links:\n  - Zeigen auf dieselbe Inode (dieselben Daten)\n  - Original löschen → Hard Link lebt weiter!\n  - Nur innerhalb desselben Dateisystems\n  - Keine Hard Links auf Verzeichnisse (außer . und ..)\n  - ls -l zeigt Link-Count in Spalte 2\n  ln original.txt hardlink.txt\n\nSymbolic Links (Symlinks):\n  - Zeigen auf den PFAD (nicht die Inode)\n  - Original löschen → Symlink ist 'dangling' (kaputt)\n  - Über Dateisystemgrenzen möglich\n  - Können auf Verzeichnisse zeigen\n  - ls -l zeigt 'l' am Anfang und '-> ziel'\n  ln -s original.txt symlink.txt\n  ln -s /var/log/syslog /home/ghost/log\n\nErkennen:\n  ls -li              # zeigt Inode-Nummer (-i)\n  ls -l               # Symlinks: lrwxrwxrwx -> ziel\n  readlink symlink    # Ziel eines Symlinks anzeigen\n\nSymlinks vs Hard Links:\n  Hard Link: gleiche Inode, kein l-Typ, kein 'dangling'\n  Symlink:   eigene Inode, l-Typ, kann dangling sein", syntax='ln original hardlink\nln -s ziel symlink', example='$ ln /etc/hosts /tmp/hosts_hard\n$ ln -s /etc/hosts /tmp/hosts_sym\n$ ls -li /etc/hosts /tmp/hosts_hard /tmp/hosts_sym\n123456 -rw-r--r-- 2 root root 221 ... /etc/hosts\n123456 -rw-r--r-- 2 root root 221 ... /tmp/hosts_hard\n789012 lrwxrwxrwx 1 root root  10 ... /tmp/hosts_sym -> /etc/hosts', task_description='Zeige Inode-Nummern von Dateien', expected_commands=['ls -li', 'ls -l'], hints=["Ein Auflistungsbefehl wie 'ls' wird benötigt.", 'Versuche: ls -li', 'Der vollständige Befehl: ls -li'], hint_text='ls -li zeigt die Inode-Nummern (erste Spalte)', quiz_questions=[QuizQuestion(question='Hard Link und Original zeigen auf dieselbe Inode. Was passiert wenn das Original gelöscht wird?', options=['A) Hard Link wird ebenfalls ungültig', 'B) Hard Link bleibt gültig — Daten existieren weiter', 'C) Hard Link wird automatisch gelöscht', 'D) Fehler — man kann Originale mit Hard Links nicht löschen'], correct='B', explanation='Hard Links zeigen auf dieselbe Inode. Daten werden erst freigegeben wenn ALLE Hard Links gelöscht sind (Link-Count = 0).', xp_value=25), QuizQuestion(question="Was ist ein 'dangling symlink'?", options=['A) Ein Symlink der auf ein Verzeichnis zeigt', 'B) Ein Symlink dessen Zieldatei nicht mehr existiert', 'C) Ein Symlink mit falschen Rechten', 'D) Ein Symlink auf ein anderes Dateisystem'], correct='B', explanation='Dangling symlink = hängender Symlink. Das Ziel wurde gelöscht oder existiert nicht. ls zeigt ihn oft in Rot.', xp_value=25)], exam_tip="Hard Link: gleiche Inode, kein l, bleibt nach rm original.\nSymlink: ln -s, 'l' am Anfang, -> zeigt Ziel, kann dangling sein.\nls -li zeigt Inode-Nummern zum Vergleich.\nHard Links nicht über Dateisystemgrenzen!", memory_tip='ln = Hard Link (gleiche Inode). ln -s = Symlink (Pfadzeiger). -s = soft/symbolic.', gear_reward=None, faction_reward=('Net Runners', 4)), Mission(mission_id='5.07', chapter=5, title='find — Der Dateisystem-Spürhund', mtype='SCAN', xp=110, speaker='ZARA Z3R0', story="Irgendwo im System versteckt sich eine Datei.\nZara Z3R0: 'find ist dein Spürhund, Ghost.\n Kein Ort ist sicher. Kein Dateiname kann sich verstecken.'", why_important='find ist eines der mächtigsten Linux-Tools.\nLPIC-1 prüft find intensiv: -name, -type, -perm, -mtime, -exec.', explanation="find — Dateien und Verzeichnisse suchen:\n\nGrundsyntax:\n  find <startpfad> <kriterien> [<aktion>]\n\nNach Name:\n  find / -name 'passwd'         # exakter Name\n  find / -name '*.log'          # Wildcard\n  find / -iname '*.LOG'         # case-insensitive\n\nNach Typ:\n  find /var -type f    # nur Dateien (f=file)\n  find /etc -type d    # nur Verzeichnisse (d=directory)\n  find /tmp -type l    # nur Symlinks (l=link)\n\nNach Rechten:\n  find / -perm 644         # exakt 644\n  find / -perm -4000       # SUID gesetzt\n  find / -perm -2000       # SGID gesetzt\n  find / -perm /222        # irgendein write-Bit\n\nNach Größe:\n  find / -size +100M       # größer als 100MB\n  find / -size -1k         # kleiner als 1 KB\n  find / -size 512c        # genau 512 Bytes\n\nNach Zeit:\n  find / -mtime -1         # geändert in letzten 24h\n  find / -mtime +30        # älter als 30 Tage\n  find / -newer /etc/hosts # neuer als /etc/hosts\n  find / -atime -7         # accessed in 7 Tagen\n\nNach Owner:\n  find / -user ghost       # Owner = ghost\n  find / -group hackers    # Gruppe = hackers\n  find / -nouser           # kein gültiger Owner\n\nAktionen:\n  find /tmp -name '*.tmp' -delete    # löschen\n  find /log -name '*.log' -exec gzip {} \\;\n  find /var -type f -exec chmod 644 {} \\;\n  find / -name '*.conf' -print0 | xargs -0 grep 'password'\n\nKombinieren:\n  find / -type f -name '*.sh' -perm -u+x  # ausführbare Shell-Skripte\n  find / -user root -perm -4000 2>/dev/null  # root SUID", syntax="find /pfad -name '*.log' -type f\nfind / -perm -4000 2>/dev/null", example="$ find /etc -name '*.conf' -type f | head -5\n/etc/ldap/ldap.conf\n/etc/nginx/nginx.conf\n/etc/ssh/sshd_config\n\n$ find / -perm -4000 2>/dev/null\n/usr/bin/passwd\n/usr/bin/sudo", task_description='Suche nach allen .conf-Dateien in /etc', expected_commands=["find /etc -name '*.conf'", 'find'], hints=["Das Verzeichnis oder die Datei befinden sich unter '/etc'. Der Befehl beginnt mit 'find'.", 'Versuche: find /etc -name ...', "Der vollständige Befehl: find /etc -name '*.conf'"], hint_text="find /etc -name '*.conf' -type f", quiz_questions=[QuizQuestion(question="Was macht 'find / -mtime -2'?", options=['A) Dateien die vor 2 Minuten geändert wurden', 'B) Dateien die in den letzten 2 × 24 Stunden geändert wurden', 'C) Dateien älter als 2 Tage', 'D) Dateien mit Modifikationszeit = 2'], correct='B', explanation='-mtime -2 = geändert in den letzten 2 Tagen (< 2×24h). + wäre älter als 2 Tage.', xp_value=25), QuizQuestion(question='find / -perm -4000 findet Dateien mit welchem Special Bit?', options=['A) Sticky Bit', 'B) SGID', 'C) SUID', 'D) Execute'], correct='C', explanation='-perm -4000: SUID-Bit gesetzt (4 = SUID in der 4-Bit-Notation).', xp_value=25)], exam_tip="find-Syntax: find <pfad> <kriterien> [<aktion>]\n-name '*.log': Wildcard in Anführungszeichen!\n-mtime -1: letzte 24h. -mtime +30: älter als 30 Tage.\n-exec befehl {} \\;  — {} = Platzhalter, \\; = Ende", memory_tip="find /pfad -type f -name '*.x' -mtime -7 -exec cmd {} \\;", gear_reward=None, faction_reward=('Net Runners', 5)), Mission(mission_id='5.08', chapter=5, title='locate & updatedb — Die Schnellsuche', mtype='SCAN', xp=65, speaker='RUST', story="find ist mächtig aber langsam auf großen Systemen.\nRust: 'locate sucht in einer Datenbank, Ghost.\n Millisekunden statt Minuten. Aber du musst sie aktuell halten.'", why_important='locate ist schnell, aber datenbankbasiert — veraltet wenn updatedb alt ist.\nLPIC-1 fragt nach Unterschied locate vs find.', explanation="locate — Schnellsuche in Datenbankindex:\n\n  locate passwd           # alle Pfade mit 'passwd'\n  locate -i PASSWD        # case-insensitive\n  locate -c passwd        # nur Anzahl ausgeben\n  locate -r '\\.conf$'    # Regex-Suche\n  locate '*.conf'         # Wildcard\n\nupdatedb — Datenbank aktualisieren:\n\n  updatedb                # als root ausführen\n  # Läuft täglich via cron automatisch\n  # Datenbank: /var/lib/mlocate/mlocate.db\n\nKonfiguration:\n  /etc/updatedb.conf      # Ausschlüsse konfigurieren\n  PRUNEPATHS=/tmp /proc /sys  # diese Pfade ignorieren\n\nlocate vs find:\n  locate: schnell (DB), kann veraltet sein\n  find:   langsam (Echtzeit), immer aktuell\n\nVerwandte Befehle:\n  which ls                # Pfad eines Befehls\n  whereis ls              # Binär + Man + Source\n  type ls                 # Shell-Typ (builtin/alias/file)", syntax='locate dateiname\nupdatedb\nwhich befehl', example='$ locate sshd_config\n/etc/ssh/sshd_config\n/usr/share/doc/openssh-server/sshd_config.gz\n\n$ which python3\n/usr/bin/python3\n\n$ whereis bash\nbash: /bin/bash /etc/bash.bashrc /usr/share/man/man1/bash.1.gz', task_description="Finde den Pfad des Befehls 'ls' mit which", expected_commands=['which ls', 'which', 'whereis ls'], hints=["Der Befehl 'which' ist der richtige Ansatz.", 'Versuche: which ls', 'Der vollständige Befehl: which ls'], hint_text='which ls zeigt wo der ls-Befehl installiert ist', quiz_questions=[QuizQuestion(question='Was ist der Unterschied zwischen locate und find?', options=['A) locate sucht in Echtzeit, find aus Datenbank', 'B) locate nutzt Datenbank (schnell), find sucht aktuell (langsam)', 'C) Kein Unterschied', 'D) locate nur für Verzeichnisse'], correct='B', explanation='locate = schnell via Datenbank (kann veraltet sein). find = langsam aber immer aktuell.', xp_value=20), QuizQuestion(question='Welcher Befehl aktualisiert die locate-Datenbank?', options=['A) locate -update', 'B) updatedb', 'C) find -update', 'D) locate --refresh'], correct='B', explanation='updatedb aktualisiert die mlocate-Datenbank. Ohne updatedb zeigt locate veraltete Ergebnisse.', xp_value=20)], exam_tip='locate = schnell aber veraltet → updatedb nötig.\nfind = langsam aber aktuell.\nwhich = Pfad eines ausführbaren Befehls.\nwhereis = Pfad + Manpage + Source.', memory_tip='locate=schnell (DB). find=aktuell (live). which=wo ist der Befehl?', gear_reward=None, faction_reward=('Net Runners', 3)), Mission(mission_id='5.09', chapter=5, title='FHS — Die Karte von NeonGrid-9', mtype='DECODE', xp=95, speaker='ZARA Z3R0', story="NeonGrid-9 hat eine Karte. Der FHS.\nOhne sie bist du ein Blinder im Datenlabyrinth.\nZara Z3R0: 'Kenn jeden Winkel des Systems, Ghost.\n /etc, /var, /usr — das sind deine Orientierungspunkte.'", why_important='FHS definiert wo Dateien leben. LPIC-1 prüft FHS-Verzeichnisse intensiv.\nKein Admin kann ohne dieses Wissen effektiv arbeiten.', explanation='FHS — Filesystem Hierarchy Standard:\n\n/          — Root: Wurzel des Systems\n/bin       — Essentielle Binaries (ls, cp, mv, bash)\n/sbin      — System-Binaries für root (init, fsck, ifconfig)\n/usr       — Sekundäre Hierarchie (User-Programme)\n  /usr/bin   — Normale Programme (python3, gcc, vim)\n  /usr/sbin  — System-Programme (apache2, nginx)\n  /usr/lib   — Bibliotheken für /usr/bin\n  /usr/local — Lokal installierte Software\n  /usr/share — Architekturunabhängige Daten\n/etc       — Konfigurationsdateien\n/var       — Variable Daten (Logs, Datenbanken, Spool)\n  /var/log   — Logdateien\n  /var/spool — Drucker- und Mail-Queues\n  /var/run   → /run — PID-Dateien (veraltet, Symlink)\n  /var/tmp   — Temporäre Dateien (bleiben nach Reboot)\n/tmp       — Temporäre Dateien (werden bei Reboot geleert)\n/home      — Heimverzeichnisse der Benutzer\n/root      — Heimverzeichnis von root\n/boot      — Boot-Dateien (Kernel, initramfs, GRUB)\n/dev       — Gerätedateien (tty, sda, null, random)\n/proc      — Virtuell: Kernel-Laufzeitinfos\n/sys       — Virtuell: Gerätehierarchie (sysfs)\n/run       — Laufzeitdaten (PID-Dateien, Sockets)\n/lib       — Bibliotheken für /bin und /sbin\n/lib64     — 64-bit Bibliotheken\n/mnt       — Temporäre Mounts\n/media     — Wechselmedien (USB, CD)\n/opt       — Optionale Add-on-Software\n/srv       — Service-Daten (Webserver, FTP)\n/lost+found — Wiederhergestellte Dateien (ext-FS)', syntax='ls /\nls /etc\nls /var/log', example='$ ls /\nbin  boot  dev  etc  home  lib  media  mnt  opt  proc  root  run  srv  sys  tmp  usr  var', task_description='Zeige den Inhalt des Root-Verzeichnisses', expected_commands=['ls /', 'ls -la /'], hints=["Das Verzeichnis oder die Datei befinden sich unter '/'. Der Befehl beginnt mit 'ls'.", 'Versuche: ls /', 'Der vollständige Befehl: ls /'], hint_text='ls / zeigt alle Top-Level-Verzeichnisse', quiz_questions=[QuizQuestion(question='Wo befinden sich Logdateien im FHS?', options=['A) /etc/logs', 'B) /tmp/log', 'C) /var/log', 'D) /usr/log'], correct='C', explanation='/var/log enthält System- und Anwendungs-Logs (syslog, auth.log, kern.log...)', xp_value=20), QuizQuestion(question='Was ist der Unterschied zwischen /tmp und /var/tmp?', options=['A) /tmp ist größer', 'B) /var/tmp bleibt nach Reboot erhalten, /tmp wird geleert', 'C) /tmp ist für root reserviert', 'D) Kein Unterschied'], correct='B', explanation='/tmp wird bei jedem Reboot geleert. /var/tmp bleibt erhalten (persistent temporary).', xp_value=20), QuizQuestion(question='In welchem Verzeichnis liegen Konfigurationsdateien?', options=['A) /usr/config', 'B) /opt', 'C) /etc', 'D) /var/config'], correct='C', explanation='/etc enthält systemweite Konfigurationsdateien (sshd_config, fstab, passwd...)', xp_value=20)], exam_tip='FHS-Fragen im LPIC-1 sind sehr häufig!\n/etc = Konfiguration. /var/log = Logs. /tmp = temporär (bei Reboot weg).\n/usr/local = selbst installierte Software.\n/proc und /sys = virtuelle Dateisysteme (kein echtes Speicher).', memory_tip='/etc=Konfiguration. /var=variabel(Logs). /tmp=temporär(weg). /usr=Programme.', gear_reward=None, faction_reward=('Net Runners', 4)), Mission(mission_id='5.10', chapter=5, title='stat / file / type — Dateien entschlüsseln', mtype='SCAN', xp=70, speaker='RUST', story="Ghost findet eine Datei ohne Endung.\nRust: 'Vertrau nie der Endung, Ghost. Vertrau dem Inhalt.\n stat, file — sie lügen nicht.'", why_important='stat, file und type sind schnelle Diagnose-Tools.\nLPIC-1 fragt nach file (Dateitype erkennen) und stat (Metadaten).', explanation="stat — Datei-Metadaten:\n\n  stat datei.txt\n  → Inode, Rechte, Owner, Größe, Zeitstempel\n  → atime (access), mtime (modify), ctime (change)\n\n  stat -c '%n %s %U' datei  # Format: Name Größe Owner\n\nfile — Dateityp erkennen:\n\n  file unbekannt.bin\n  → ELF 64-bit LSB executable\n  file bild.jpg\n  → JPEG image data\n  file skript\n  → Bourne-Again shell script\n  file /dev/sda\n  → block special\n\ntype — Shell-Befehl-Typ:\n\n  type ls\n  → ls is /bin/ls\n  type cd\n  → cd is a shell builtin\n  type ll\n  → ll is aliased to 'ls -l'\n\nZeitstempel-Typen:\n  atime = letzter Zugriff (access)\n  mtime = letzte Inhaltsänderung (modify)\n  ctime = letzte Metadaten-Änderung (change: chmod, chown)\n  Achtung: ctime ≠ creation time!", syntax='stat datei\nfile datei\ntype befehl', example='$ stat /etc/passwd\n  File: /etc/passwd\n  Size: 2456      Blocks: 8    IO Block: 4096\n  Inode: 131073   Links: 1\n  Access: (0644/-rw-r--r--)  Uid: (0/root)\n  Access: 2089-01-15 07:59:58\n  Modify: 2089-01-14 12:00:01\n  Change: 2089-01-14 12:00:01', task_description='Zeige Metadaten einer Datei mit stat', expected_commands=['stat', 'file'], hints=["Ein Auflistungsbefehl wie 'stat' wird benötigt.", 'Der Befehl selbst ist: stat', 'Der vollständige Befehl: stat'], hint_text='stat /etc/passwd zeigt alle Metadaten einer Datei', quiz_questions=[QuizQuestion(question='Was bedeutet ctime bei einer Datei?', options=['A) Creation time (Erstellungszeit)', 'B) Change time (Metadaten geändert)', 'C) Current time', 'D) Copy time'], correct='B', explanation='ctime ≠ Creation! ctime = change time (Metadaten wie Rechte, Owner geändert). mtime = Inhalt geändert.', xp_value=20), QuizQuestion(question='Welcher Befehl zeigt den tatsächlichen Typ einer Datei (z.B. ob sie wirklich eine Textdatei ist)?', options=['A) stat datei', 'B) ls -l datei', 'C) file datei', 'D) type datei'], correct='C', explanation='file erkennt Dateitype am Inhalt (Magic Bytes), nicht an der Endung.', xp_value=20)], exam_tip='ctime ≠ creation time! ctime = change time (Metadaten geändert).\nmtime = Inhalt geändert. atime = zugegriffen.\nfile erkennt Dateityp am Magic Number — nicht an der Endung.\ntype = Shell-Builtin vs externem Befehl.', memory_tip='stat=Metadaten. file=Dateityp(Inhalt). ctime=change(chmod/chown)≠creation.', gear_reward=None, faction_reward=('Net Runners', 3)), Mission(mission_id='5.11', chapter=5, title='umask — Schablone setzen & konfigurieren', mtype='SCAN', xp=80, speaker='ZARA Z3R0', story="Jede neue Datei in NeonGrid-9 trägt eine unsichtbare Schablone.\nWoher kommt sie? /etc/profile. ~/.bashrc. login.defs.\nZara Z3R0: 'umask 022 vs 002 — versteh den Unterschied, Ghost.\n Eine falsche Schablone öffnet das System für jeden.'", why_important='umask bestimmt Standardrechte und wird system- wie benutzerweit konfiguriert.\nLPIC-1 fragt nach Konfigurationsorten und dem Unterschied 022 vs 002.', explanation='umask setzen — temporär und dauerhaft:\n\nTemporär (nur aktuelle Shell-Sitzung):\n  umask 022      # setzt Maske auf 022\n  umask 002      # setzt Maske auf 002\n  umask -S       # symbolisch anzeigen\n\nDauerhaft für alle Benutzer:\n  /etc/profile   — Systemweite Shell-Konfiguration\n  /etc/login.defs— Login-Defaults (UMASK-Zeile)\n  /etc/bashrc    — Bash-spezifisch systemweit\n\nDauerhaft für einen Benutzer:\n  ~/.bashrc      — bash-Konfiguration des Users\n  ~/.profile     — POSIX-kompatibel\n\n022 vs 002:\n  umask 022:\n    Datei:       666 - 022 = 644 (rw-r--r--)\n    Verzeichnis: 777 - 022 = 755 (rwxr-xr-x)\n    → Group und Other haben kein Schreibrecht\n    → Standard für normale Benutzer\n\n  umask 002:\n    Datei:       666 - 002 = 664 (rw-rw-r--)\n    Verzeichnis: 777 - 002 = 775 (rwxrwxr-x)\n    → Group darf schreiben, Other nicht\n    → Nützlich für kollaborative Gruppenumgebungen\n\nKonfiguration in /etc/login.defs:\n  UMASK    022\n  # oder\n  UMASK    002', syntax='umask\numask 022\numask 002\numask -S', example='$ grep -i umask /etc/profile\numask 022\n\n$ umask\n0022\n$ umask 002 && umask\n0002\n$ touch testdatei && ls -l testdatei\n-rw-rw-r-- 1 ghost ghost 0 Jan 15 08:00 testdatei', task_description='Zeige den aktuellen umask-Wert symbolisch', expected_commands=['umask -S', 'umask'], hints=["Ein Auflistungsbefehl wie 'umask' wird benötigt.", 'Versuche: umask -S', 'Der vollständige Befehl: umask -S'], hint_text='umask -S zeigt die Maske im symbolischen Format', quiz_questions=[QuizQuestion(question='Wo setzt man umask dauerhaft für ALLE Benutzer?', options=['A) ~/.bashrc', 'B) /etc/profile oder /etc/login.defs', 'C) /tmp/umask.conf', 'D) /proc/sys/fs/umask'], correct=1, explanation='/etc/profile gilt systemweit bei Login. /etc/login.defs hat eine UMASK-Zeile für Login-Shells.', xp_value=15), QuizQuestion(question='umask 002: welche Rechte hat ein neues Verzeichnis?', options=['A) 755', 'B) 644', 'C) 775', 'D) 777'], correct=2, explanation='Verzeichnis-Basis 777 - 002 = 775 (rwxrwxr-x). Group darf schreiben, Other nur lesen+betreten.', xp_value=15)], exam_tip='umask 022 → Datei 644, Verzeichnis 755 (Standard).\numask 002 → Datei 664, Verzeichnis 775 (Gruppen-Kollaboration).\nSystemweit: /etc/profile oder /etc/login.defs.\nBenutzerweit: ~/.bashrc oder ~/.profile.', memory_tip='022=Standard(andere nur lesen). 002=Gruppe darf schreiben. /etc/profile=systemweit.', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.12', chapter=5, title='Sticky Bit — /tmp und das Lösch-Tabu', mtype='SCAN', xp=85, speaker='VECTOR', story="Jeder Hacker schreibt in /tmp. Aber niemand darf fremde Dateien löschen.\nVector erklärt: 'Das Sticky Bit, Ghost.\n chmod +t macht /tmp zur sicheren Gemeinschaftsfläche.\n Dein Müll — dein Problem.'", why_important='Das Sticky Bit auf Verzeichnissen schützt gemeinsame Bereiche.\nLPIC-1 prüft /tmp (1777) und warum Sticky Bit nötig ist.', explanation="Sticky Bit auf Verzeichnissen:\n\n  Wenn gesetzt: Nur der Datei-Owner (oder root) darf\n                die eigene Datei löschen oder umbenennen.\n  Auch wenn das Verzeichnis für alle beschreibbar ist!\n\nSetzen:\n  chmod +t /shared        # Sticky Bit setzen\n  chmod 1777 /shared      # 1=Sticky + 777=rwxrwxrwx\n  chmod o+t /shared       # äquivalent\n\nEntfernen:\n  chmod -t /shared\n  chmod 0777 /shared      # 0 = keine Special Bits\n\nErkennen in ls -l:\n  drwxrwxrwt — 't' an letzter Stelle = Sticky Bit gesetzt\n  drwxrwxrwT — 'T' (groß) = Sticky gesetzt, aber other-x fehlt\n\nBeispiel /tmp:\n  $ ls -ld /tmp\n  drwxrwxrwt 18 root root 4096 Jan 15 08:00 /tmp\n  ↑ 't' = Sticky Bit aktiv!\n\nPraktische Auswirkung:\n  User ghost erstellt /tmp/ghost_file.txt\n  User runner KANN die Datei NICHT löschen\n  (auch wenn /tmp 777 ist)\n  Nur ghost oder root können ghost_file.txt löschen.\n\nOktalwert: 1xxx\n  chmod 1777 /tmp   → rwxrwxrwt\n  chmod 1755 /dir   → rwxr-xr-t", syntax='chmod +t /verzeichnis\nchmod 1777 /verzeichnis\nls -ld /tmp', example='$ ls -ld /tmp\ndrwxrwxrwt 18 root root 4096 Jan 15 08:00 /tmp\n\n$ mkdir /shared && chmod 1777 /shared\n$ ls -ld /shared\ndrwxrwxrwt 2 root root 4096 Jan 15 08:01 /shared', task_description='Zeige das Sticky Bit von /tmp', expected_commands=['ls -ld /tmp', 'ls -ld'], hints=["Das Verzeichnis oder die Datei befinden sich unter '/tmp'. Der Befehl beginnt mit 'ls'.", 'Versuche: ls -ld /tmp', 'Der vollständige Befehl: ls -ld /tmp'], hint_text="ls -ld /tmp zeigt das 't' am Ende der Rechte-Spalte", quiz_questions=[QuizQuestion(question='Sticky Bit ist auf /shared gesetzt (rwxrwxrwx+t). User B will Datei von User A löschen. Was passiert?', options=['A) Löschen erlaubt — das Verzeichnis ist für alle beschreibbar', "B) Löschen verboten — nur A oder root dürfen A's Datei löschen", 'C) B bekommt eine Warnung, kann aber trotzdem löschen', 'D) Sticky Bit betrifft nur Dateien, nicht Verzeichnisse'], correct=1, explanation='Sticky Bit schützt Dateien in gemeinsamen Verzeichnissen. Nur der Datei-Owner und root dürfen die Datei löschen/umbenennen.', xp_value=15), QuizQuestion(question='Welcher chmod-Befehl setzt Sticky Bit + volle Rechte für alle?', options=['A) chmod 7777', 'B) chmod 1777', 'C) chmod +t+777', 'D) chmod 4777'], correct=1, explanation='1777: 1=Sticky Bit, 777=rwxrwxrwx. Ergibt drwxrwxrwt.', xp_value=15)], exam_tip="Sticky Bit = 1xxx. ls zeigt 't' (oder 'T' wenn other-x fehlt).\n/tmp hat 1777 = rwxrwxrwt.\nWirkung: Nur Datei-Owner oder root darf im Sticky-Verzeichnis löschen.", memory_tip='Sticky=t=nur Owner löscht. /tmp=1777=drwxrwxrwt. +t=chmod setzen.', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.13', chapter=5, title='SGID auf Verzeichnisse — Gruppenvererbung', mtype='CONSTRUCT', xp=90, speaker='ZARA Z3R0', story="Das Team-Verzeichnis ist ein Problem.\nJeder speichert Dateien mit seiner eigenen Gruppe.\nZara Z3R0: 'SGID auf das Verzeichnis, Ghost.\n Jede neue Datei erbt die Gruppe — automatisch.'", why_important='SGID auf Verzeichnisse aktiviert Gruppenvererbung für neue Dateien.\nLPIC-1 prüft den Unterschied SGID auf Datei vs. Verzeichnis.', explanation="SGID auf Verzeichnissen:\n\n  Wenn SGID auf ein Verzeichnis gesetzt ist:\n  → Neue Dateien und Unterverzeichnisse erben die GRUPPE\n    des Verzeichnisses (statt der primären Gruppe des Users).\n\nSetzen:\n  chmod g+s /team        # SGID setzen\n  chmod 2755 /team       # 2=SGID + 755\n  chmod 2770 /team       # SGID + rwxrwx---\n\nErkennen in ls -l:\n  drwxrwsr-x — 's' bei Group-x = SGID gesetzt\n  drwxrwSr-x — 'S' (groß) = SGID gesetzt, aber group-x fehlt\n\nBeispiel — Team-Verzeichnis:\n  $ mkdir /projects\n  $ chown root:developers /projects\n  $ chmod 2775 /projects\n  $ ls -ld /projects\n  drwxrwsr-x 2 root developers 4096 Jan 15 /projects\n\n  → User ghost (Mitglied von developers) erstellt:\n  $ touch /projects/neues_file.py\n  $ ls -l /projects/neues_file.py\n  -rw-rw-r-- 1 ghost developers 0 Jan 15 ... neues_file.py\n           ↑ Gruppe 'developers' geerbt — nicht ghost's primäre Gruppe!\n\nOktalwert: 2xxx\n  2755 = drwxr-sr-x\n  2770 = drwxrws--- (nur Gruppenmitglieder)", syntax='chmod g+s /verzeichnis\nchmod 2775 /team\nls -ld /team', example="$ mkdir /collab && chown root:devs /collab\n$ chmod 2770 /collab\n$ ls -ld /collab\ndrwxrws--- 2 root devs 4096 Jan 15 08:00 /collab\n\n# Neues File im Verzeichnis erbt Gruppe 'devs':\n$ touch /collab/projekt.txt && ls -l /collab/projekt.txt\n-rw-rw---- 1 ghost devs 0 Jan 15 08:01 /collab/projekt.txt", task_description='Zeige SGID-gesetzte Verzeichnisse', expected_commands=['ls -ld', 'find / -perm -2000 -type d'], hints=["Ein Auflistungsbefehl wie 'ls' wird benötigt.", 'Versuche: ls -ld', 'Der vollständige Befehl: ls -ld'], hint_text="ls -ld /verzeichnis zeigt 's' bei group-x wenn SGID gesetzt ist", quiz_questions=[QuizQuestion(question="SGID ist auf /team gesetzt. Gruppe von /team ist 'devs'. Ghost erstellt /team/code.py. Welche Gruppe hat code.py?", options=['A) ghost (primäre Gruppe von ghost)', 'B) root', 'C) devs (Gruppe des Verzeichnisses geerbt)', 'D) nobody'], correct=2, explanation='SGID auf Verzeichnis: neue Dateien erben die Gruppe des Verzeichnisses. Das ist genau der Zweck dieser Funktion.', xp_value=15), QuizQuestion(question='Was ist der Unterschied zwischen SGID auf einer Datei und SGID auf einem Verzeichnis?', options=['A) Kein Unterschied', 'B) Datei: Programm läuft mit Gruppen-Rechten des Owners. Verzeichnis: neue Dateien erben die Gruppe', 'C) Verzeichnis: Programm läuft mit Gruppenrechten. Datei: Gruppenvererbung', 'D) SGID funktioniert nur auf Dateien'], correct=1, explanation='SGID auf Datei = Programm läuft mit Gruppe des Owners (wie SUID aber für Gruppe). SGID auf Verzeichnis = Gruppenvererbung für neue Einträge.', xp_value=15)], exam_tip="SGID auf Verzeichnis = Gruppenvererbung für neue Dateien.\nchmod g+s dir  oder  chmod 2xxx dir.\nls zeigt 's' (oder 'S') bei group-x Position.\nNützlich für Team-Verzeichnisse wo alle Mitglieder dieselbe Gruppe nutzen sollen.", memory_tip="SGID+Verz=Gruppe vererbt. g+s=setzen. 2xxx=Oktal. 's' bei group-x.", gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.14', chapter=5, title='ACL Grundlagen — Feingranulare Zugriffsrechte', mtype='SCAN', xp=95, speaker='VECTOR', story="Die standard rwx-Matrix reicht nicht mehr.\nGhost braucht: user ghost=rw, group staff=r, sonst nichts.\nVector: 'ACLs, Ghost. Access Control Lists.\n Berechtigungen für jeden einzelnen User und jede Gruppe.'", why_important='ACLs erweitern das klassische Unix-Berechtigungssystem.\nLPIC-1 prüft getfacl und setfacl für spezifische User- und Gruppenrechte.', explanation="ACL — Access Control List:\n\nVoraussetzung: Dateisystem mit ACL-Unterstützung\n  (ext4, xfs etc. — meist standardmäßig aktiv)\n\nACL lesen:\n  getfacl datei.txt\n  getfacl /var/data/\n\nBeispiel getfacl Ausgabe:\n  # file: datei.txt\n  # owner: root\n  # group: admins\n  user::rw-          ← Owner\n  user:ghost:rw-     ← spezifischer User\n  group::r--         ← owning group\n  group:staff:r--    ← spezifische Gruppe\n  mask::rw-          ← effektive Maske\n  other::---         ← alle anderen\n\nACL setzen:\n  setfacl -m u:ghost:rw datei.txt  # User ghost: lesen+schreiben\n  setfacl -m g:staff:r  datei.txt  # Gruppe staff: nur lesen\n  setfacl -m u:ghost:rwx dir/      # User ghost: alle Rechte auf Verzeichnis\n  setfacl -m o::--- datei.txt       # Other: keine Rechte\n\nACL-Syntax:\n  u:<user>:<rechte>   — User-Eintrag\n  g:<group>:<rechte>  — Gruppen-Eintrag\n  o::<rechte>         — Other\n  m::<rechte>         — Maske\n\nIn ls -l erkennen:\n  -rw-rw-r--+   ← '+' am Ende = ACL vorhanden!", syntax='getfacl datei\nsetfacl -m u:ghost:rw datei\nsetfacl -m g:staff:r datei', example="$ setfacl -m u:ghost:rw /etc/projekt.conf\n$ setfacl -m g:staff:r /etc/projekt.conf\n$ getfacl /etc/projekt.conf\n# file: /etc/projekt.conf\nuser::rw-\nuser:ghost:rw-\ngroup::r--\ngroup:staff:r--\nmask::rw-\nother::---\n\n$ ls -l /etc/projekt.conf\n-rw-rw----+ 1 root root 512 Jan 15 ... /etc/projekt.conf\n          ↑ '+' zeigt ACL-Einträge!", task_description='Zeige ACLs einer Datei mit getfacl', expected_commands=['getfacl', 'ls -l'], hints=["Ein Auflistungsbefehl wie 'getfacl' wird benötigt.", 'Der Befehl selbst ist: getfacl', 'Der vollständige Befehl: getfacl'], hint_text='getfacl datei.txt zeigt alle ACL-Einträge der Datei', quiz_questions=[QuizQuestion(question="Woran erkennt man in 'ls -l' Ausgabe, dass eine Datei ACLs hat?", options=["A) An einem '@' vor den Rechten", "B) An einem '+' nach den Rechten", "C) An einem 'a' im Dateityp-Buchstaben", 'D) Durch eine andere Farbe'], correct=1, explanation="Ein '+' am Ende der Berechtigungszeichenkette (z.B. -rw-rw-r--+) signalisiert, dass ACL-Einträge existieren.", xp_value=15), QuizQuestion(question="Welcher Befehl gibt User 'analyst' Leserecht auf config.txt via ACL?", options=['A) chmod u:analyst:r config.txt', 'B) setfacl -m u:analyst:r config.txt', 'C) chown analyst config.txt', 'D) acl -add analyst:r config.txt'], correct=1, explanation='setfacl -m = modify ACL. u:analyst:r = User analyst bekommt Leserecht.', xp_value=15)], exam_tip="getfacl = ACL lesen. setfacl -m = ACL setzen (modify).\nSyntax: setfacl -m u:<user>:<rwx> datei\n'+' in ls -l Ausgabe = ACL vorhanden.\nmask begrenzt die effektiven Rechte aller ACL-Einträge (außer owner+other).", memory_tip="getfacl=lesen. setfacl -m=setzen. u:user:rwx=User-ACL. '+'=ACL vorhanden.", gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.15', chapter=5, title='ACL setzen & entfernen — setfacl -x und -b', mtype='CONSTRUCT', xp=95, speaker='ZARA Z3R0', story="Ghost hat zu viele ACL-Einträge gesetzt.\nJetzt muss er aufräumen — einzelne Einträge löschen oder alles zurücksetzen.\nZara Z3R0: 'setfacl -x für einzelne. setfacl -b für alle, Ghost.\n Versteh die getfacl-Ausgabe und du kontrollierst jeden Zugang.'", why_important='ACLs entfernen und die getfacl-Ausgabe interpretieren ist LPIC-1-Prüfungsstoff.\nDie mask-Zeile wird oft missverstanden.', explanation="ACL-Einträge entfernen:\n\nEinzelnen Eintrag entfernen:\n  setfacl -x u:ghost datei.txt      # User ghost entfernen\n  setfacl -x g:staff datei.txt      # Gruppe staff entfernen\n\nAlle ACLs entfernen (zurück auf standard Unix-Rechte):\n  setfacl -b datei.txt              # alle ACL-Einträge löschen\n\nDefault-ACLs für Verzeichnisse:\n  setfacl -d -m u:ghost:rwx /team/  # Default-ACL setzen\n  → Neue Dateien im Verzeichnis erben diese ACL automatisch\n  setfacl -k /team/                 # Default-ACLs entfernen\n\ngetfacl Ausgabe lesen:\n  # file: config.txt\n  # owner: root          ← Datei-Owner\n  # group: sysadmin      ← Datei-Gruppe\n  user::rw-              ← Owner-Rechte (Base-ACL)\n  user:ghost:rw-         ← User ghost: rw\n  group::r--             ← Gruppe sysadmin: r\n  group:devs:rw-         ← Gruppe devs: rw\n  mask::rw-              ← Effektive Maske: begrenzt ACL-Einträge\n  other::---             ← Andere: keine Rechte\n\n  WICHTIG: mask\n  - mask::rw- bedeutet: ACL-Einträge können maximal rw haben\n  - Selbst wenn user:ghost:rwx gesetzt → effektiv nur rw (mask begrenzt)\n  - mask wird automatisch aktualisiert wenn man ACLs setzt\n\nDateien mit ACLs finden:\n  getfacl -R /etc 2>/dev/null | grep 'user:'\n  ls -la /etc | grep '+'", syntax='setfacl -x u:ghost datei\nsetfacl -b datei\ngetfacl -R /verzeichnis', example="$ setfacl -m u:ghost:rwx /data/file.txt\n$ getfacl /data/file.txt | grep ghost\nuser:ghost:rwx\n\n$ setfacl -x u:ghost /data/file.txt\n$ getfacl /data/file.txt | grep ghost\n(keine Ausgabe — Eintrag entfernt)\n\n$ setfacl -b /data/file.txt\n$ ls -l /data/file.txt\n-rw-r--r-- 1 root root 512 ...  (kein '+' mehr!)", task_description='Setze eine ACL und entferne sie wieder', expected_commands=['setfacl', 'getfacl'], hints=["Der Befehl 'setfacl' ist der richtige Ansatz.", 'Der Befehl selbst ist: setfacl', 'Der vollständige Befehl: setfacl'], hint_text='setfacl -b datei entfernt alle ACL-Einträge auf einmal', quiz_questions=[QuizQuestion(question='Welcher Befehl entfernt ALLE ACL-Einträge einer Datei?', options=['A) setfacl -x all datei', 'B) setfacl -b datei', 'C) getfacl -d datei', 'D) chmod -acl datei'], correct=1, explanation='setfacl -b = blanket remove = alle ACL-Einträge löschen und zur normalen Unix-Berechtigung zurückkehren.', xp_value=15), QuizQuestion(question="Was bedeutet 'mask::rw-' in der getfacl-Ausgabe?", options=['A) Der Owner hat rw-Rechte', 'B) Die maximalen effektiven Rechte für benannte ACL-Einträge sind rw', 'C) Alle anderen User haben rw-Rechte', 'D) Das Dateisystem hat nur rw-Modus'], correct=1, explanation='mask begrenzt die effektiven Rechte aller benannten User/Gruppen-ACLs. Auch wenn user:x:rwx gesetzt ist, gilt effektiv nur rw wenn mask=rw-.', xp_value=15)], exam_tip='setfacl -x u:user datei = einzelnen User-ACL-Eintrag entfernen.\nsetfacl -b datei = alle ACLs entfernen (back to normal).\nsetfacl -d -m ... = Default-ACL für Verzeichnis (Vererbung).\nmask in getfacl = maximale effektive Rechte für ACL-Einträge.', memory_tip='-x=einen entfernen. -b=alle entfernen(blank). -d=default(vererben). mask=maximale ACL-Rechte.', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.16', chapter=5, title='chattr & lsattr — Unveränderliche Dateien', mtype='SCAN', xp=85, speaker='VECTOR', story="root kann alles ändern. Oder doch nicht?\nVector flüstert: 'chattr +i, Ghost.\n immutable flag. Selbst root kann die Datei dann nicht löschen.\n /etc schützen — so macht man es wirklich sicher.'", why_important='chattr und lsattr sind erweiterte Dateiattribute jenseits von rwx.\nLPIC-1 prüft das immutable (+i) und append-only (+a) Flag.', explanation="chattr — Change Attribute:\n\n  chattr +i datei    # immutable — NIEMAND kann ändern/löschen\n  chattr -i datei    # immutable entfernen\n  chattr +a datei    # append-only — nur anhängen erlaubt\n  chattr -a datei    # append-only entfernen\n  chattr +i -R /etc  # rekursiv (nur root)\n\nlsattr — List Attribute:\n\n  lsattr datei.txt\n  lsattr -R /etc     # rekursiv\n  lsattr -a /etc     # alle inkl. versteckte\n\nWichtige Attribute:\n  +i (immutable):\n    - Datei kann nicht gelöscht, umbenannt oder geändert werden\n    - AUCH root ist gesperrt!\n    - Nur root kann das Flag entfernen\n    - Schützt kritische Systemdateien\n\n  +a (append-only):\n    - Datei kann nur erweitert werden (Anfügen)\n    - Vorhandene Daten können nicht überschrieben werden\n    - Perfekt für Logdateien\n\n  +e (extent format) — meist automatisch bei ext4\n  +s (secure delete) — Inhalt bei Löschung überschreiben\n  +u (undeletable) — Inhalt bleibt nach Löschung\n\nlsattr Ausgabe:\n  ----i--------e-- datei.txt   ← 'i' = immutable\n  -----a-------e-- logfile     ← 'a' = append-only\n  -------------e-- normal.txt  ← nur extent-flag", syntax='chattr +i /etc/passwd\nlsattr /etc/passwd\nchattr -i /etc/passwd', example="$ chattr +i /etc/resolv.conf\n$ lsattr /etc/resolv.conf\n----i--------e-- /etc/resolv.conf\n\n$ rm /etc/resolv.conf\nrm: cannot remove '/etc/resolv.conf': Operation not permitted\n\n$ chattr -i /etc/resolv.conf   # immutable entfernen (nur root)\n$ lsattr /etc/resolv.conf\n-------------e-- /etc/resolv.conf", task_description='Zeige Attribute einer Datei mit lsattr', expected_commands=['lsattr', 'lsattr /etc/passwd'], hints=["Ein Auflistungsbefehl wie 'lsattr' wird benötigt.", 'Der Befehl selbst ist: lsattr', 'Der vollständige Befehl: lsattr'], hint_text='lsattr datei zeigt erweiterte Dateiattribute an', quiz_questions=[QuizQuestion(question='chattr +i wurde auf /etc/passwd gesetzt. Was kann root mit der Datei tun?', options=['A) Alles — root hat immer alle Rechte', 'B) Nichts — immutable blockiert auch root (außer chattr -i)', 'C) root kann lesen aber nicht schreiben', 'D) root kann löschen aber nicht ändern'], correct=1, explanation='immutable (+i) blockiert alle Änderungen, auch für root. Nur root kann das Flag selbst mit chattr -i entfernen.', xp_value=15), QuizQuestion(question='Für welche Art von Datei ist chattr +a (append-only) besonders sinnvoll?', options=['A) Konfigurationsdateien in /etc', 'B) Logdateien die nur wachsen sollen', 'C) Binärdateien in /bin', 'D) Passwortdateien'], correct=1, explanation='+a = append-only. Neue Einträge können angehängt werden, aber bestehende Inhalte nicht überschrieben. Ideal für Audit-Logs.', xp_value=15)], exam_tip="chattr +i = immutable (niemand kann ändern/löschen, auch root nicht).\nchattr +a = append-only (nur anhängen, kein überschreiben).\nlsattr zeigt Attribute: 'i' und 'a' in der Flags-Spalte.\nNur root kann chattr +i/-i ausführen.", memory_tip='chattr +i=immutable(niemand ändert). +a=append-only(nur anhängen). lsattr=zeigen.', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.17', chapter=5, title='find mit Berechtigungen — SUID-Dateien aufspüren', mtype='CONSTRUCT', xp=90, speaker='ZARA Z3R0', story="Jemand hat heimlich SUID-Dateien auf NeonGrid-9 versteckt.\nPotenzielle Privilege-Escalation-Vektoren.\nZara Z3R0: 'find / -perm /4000, Ghost.\n Finde die SUID-Dateien bevor die andere Seite sie nutzt.'", why_important='find mit -perm ist eine wichtige Sicherheits-Technik.\nLPIC-1 prüft die Unterschiede zwischen -perm, -perm -, -perm / und -perm +.', explanation='find -perm — Berechtigungen als Suchkriterium:\n\nExakte Übereinstimmung:\n  find /etc -perm 644       # genau 644\n  find / -perm 4755         # genau SUID+755\n\nTeilweise Übereinstimmung (alle Bits müssen gesetzt sein):\n  find / -perm -4000        # SUID-Bit gesetzt (mindestens)\n  find / -perm -2000        # SGID-Bit gesetzt\n  find / -perm -1000        # Sticky Bit gesetzt\n  find / -perm -o+w         # Other hat Schreibrecht\n  find / -perm -0002        # Other-write gesetzt\n\nMindestens eines der Bits (OR-Logik):\n  find / -perm /4000        # SUID oder...\n  find / -perm /6000        # SUID ODER SGID gesetzt\n  find / -perm /0222        # irgendein write-Bit gesetzt\n\nSicherheits-relevante Suchen:\n  find / -perm /4000 -type f 2>/dev/null   # alle SUID-Dateien\n  find / -perm /6000 -type f 2>/dev/null   # SUID oder SGID\n  find / -perm -o+w -type f 2>/dev/null    # world-writable Dateien\n  find / -nouser 2>/dev/null                # Dateien ohne Owner\n  find / -nogroup 2>/dev/null               # Dateien ohne Gruppe\n\nMit Ausgabe kombinieren:\n  find / -perm /4000 -exec ls -l {} \\;     # Details zeigen\n  find / -perm /4000 -ls                    # kompaktere Ausgabe', syntax='find / -perm /4000 -type f 2>/dev/null\nfind / -perm -o+w -type f', example='$ find /usr/bin -perm /4000 -type f 2>/dev/null\n/usr/bin/passwd\n/usr/bin/sudo\n/usr/bin/su\n/usr/bin/newgrp\n\n$ find / -perm -o+w -type f 2>/dev/null | head -5\n/tmp/testfile\n/var/tmp/cache.tmp', task_description='Suche SUID-Dateien in /usr/bin', expected_commands=['find /usr/bin -perm /4000', 'find'], hints=["Das Verzeichnis oder die Datei befinden sich unter '/usr/bin'. Der Befehl beginnt mit 'find'.", 'Versuche: find /usr/bin -perm ...', 'Der vollständige Befehl: find /usr/bin -perm /4000'], hint_text='find /usr/bin -perm /4000 -type f sucht SUID-Dateien', quiz_questions=[QuizQuestion(question="Was ist der Unterschied zwischen 'find -perm -4000' und 'find -perm /4000'?", options=['A) Kein Unterschied', 'B) -4000: SUID muss gesetzt sein (und ggf. andere). /4000: SUID ODER andere Bits', 'C) /4000 ist veraltet und funktioniert nicht mehr', 'D) -4000 sucht exakt 4000, /4000 sucht alles mit 4 am Anfang'], correct=1, explanation='-perm -XXXX = alle angegebenen Bits müssen gesetzt sein (AND). -perm /XXXX = mindestens eines der Bits muss gesetzt sein (OR).', xp_value=15), QuizQuestion(question='find / -perm -o+w -type f findet was?', options=['A) Dateien die nur der Owner schreiben kann', 'B) World-writable Dateien (other hat Schreibrecht)', 'C) Dateien ohne Schreibrecht', 'D) Dateien mit ausführbarem Schreibschutz'], correct=1, explanation="-perm -o+w = 'other' muss write-Bit haben. World-writable Dateien sind ein Sicherheitsrisiko.", xp_value=15)], exam_tip="find -perm -4000 = SUID-Bit muss gesetzt sein (mindestens).\nfind -perm /6000 = SUID ODER SGID gesetzt.\nfind -perm -o+w = world-writable Dateien (Sicherheitsrisiko).\n2>/dev/null unterdrückt 'Permission denied'-Fehler bei systemweiter Suche.", memory_tip='-perm -X=alle Bits gesetzt. -perm /X=mindestens ein Bit. /4000=SUID. /2000=SGID.', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.18', chapter=5, title='stat — Berechtigungen und Inode im Detail', mtype='SCAN', xp=75, speaker='VECTOR', story="ls -l zeigt Berechtigungen. Aber stat zeigt alles.\nVector: 'Inode, Blocks, alle Zeitstempel, Oktalrechte.\n stat ist der forensische Blick auf eine Datei, Ghost.\n Manchmal braucht man mehr als ls.'", why_important='stat zeigt detaillierte Datei-Metadaten inklusive Oktalnotation der Rechte.\nLPIC-1 prüft Zeitstempel-Typen (atime, mtime, ctime) und Inode-Informationen.', explanation="stat — Detaillierte Datei-Informationen:\n\nGrundnutzung:\n  stat datei.txt\n  stat /etc/passwd\n  stat /tmp          # Verzeichnis\n\nAusgabe-Felder:\n  File:    — Dateiname und Symlink-Ziel\n  Size:    — Größe in Bytes\n  Blocks:  — Allozierte Blöcke auf Disk\n  IO Block:— Blockgröße des Dateisystems\n  Inode:   — Inode-Nummer\n  Links:   — Hard-Link-Zähler\n  Access:  (Oktal/symbolic)  Uid: Owner  Gid: Gruppe\n  Access:  — atime (letzter Zugriff)\n  Modify:  — mtime (letzter Inhalts-Änderung)\n  Change:  — ctime (letzte Metadaten-Änderung)\n  Birth:   — Erstellungsdatum (wenn vom FS unterstützt)\n\nFormatierte Ausgabe:\n  stat -c '%n %a' datei     # Name + Oktalrechte\n  stat -c '%n %U %G' datei  # Name + Owner + Group\n  stat -c '%s' datei        # nur Größe\n  stat -c '%i' datei        # nur Inode-Nummer\n\nFormat-Codes:\n  %n = Dateiname\n  %a = Rechte oktal\n  %A = Rechte symbolisch (-rwxr-xr-x)\n  %U = Owner-Name\n  %G = Gruppen-Name\n  %s = Dateigröße\n  %i = Inode-Nummer\n  %h = Hard-Link-Zähler\n\nZeitstempel-Typen:\n  atime = access time (letzter Lesezugriff)\n  mtime = modify time (letzter Inhalts-Write)\n  ctime = change time (Metadaten: chmod, chown, rename)\n  ctime ≠ creation time!", syntax="stat datei\nstat -c '%n %a %U' datei\nstat /etc/passwd", example="$ stat /etc/passwd\n  File: /etc/passwd\n  Size: 2456\t\tBlocks: 8\t IO Block: 4096  regular file\nDevice: fd00h/64768d\tInode: 131073\t Links: 1\nAccess: (0644/-rw-r--r--)  Uid: (    0/    root)   Gid: (    0/    root)\nAccess: 2089-01-15 07:59:58.000\nModify: 2089-01-14 12:00:01.000\nChange: 2089-01-14 12:00:01.000\n\n$ stat -c '%n %a' /etc/passwd\n/etc/passwd 644", task_description='Zeige die Oktalrechte einer Datei mit stat', expected_commands=['stat', "stat -c '%a' /etc/passwd"], hints=["Ein Auflistungsbefehl wie 'stat' wird benötigt.", 'Der Befehl selbst ist: stat', 'Der vollständige Befehl: stat'], hint_text="stat -c '%a' datei zeigt nur die Oktalrechte", quiz_questions=[QuizQuestion(question="Was zeigt 'stat -c '%a'' einer Datei?", options=['A) Das access time (atime) der Datei', 'B) Die Oktalnotation der Dateirechte', 'C) Den Owner-Namen', 'D) Die Inode-Nummer'], correct=1, explanation='%a in stat -c Formatstring = Oktalrechte (z.B. 644). %A wäre die symbolische Form (-rw-r--r--).', xp_value=15), QuizQuestion(question='ctime in stat Ausgabe bedeutet:', options=['A) creation time — wann die Datei erstellt wurde', 'B) change time — wann Metadaten zuletzt geändert wurden (chmod, chown)', 'C) content time — wann der Inhalt zuletzt gelesen wurde', 'D) copy time — wann die Datei kopiert wurde'], correct=1, explanation="ctime = change time = letzte Metadaten-Änderung (Rechte, Owner, Name). Wird bei chmod/chown aktualisiert. Nicht zu verwechseln mit 'creation time'.", xp_value=15)], exam_tip="stat zeigt: Inode, Links, Rechte (oktal+symbolisch), Owner, alle 3 Zeitstempel.\nctime = Metadaten-Änderung (chmod/chown) — NICHT creation time!\nmtime = Inhalts-Änderung. atime = letzter Lesezugriff.\nstat -c '%a' datei = nur Oktalrechte ausgeben.", memory_tip='stat=alles über Datei. ctime=change(chmod). mtime=modify(Inhalt). atime=access(lesen).', gear_reward=None, faction_reward=('Root Collective', 10)), Mission(mission_id='5.19', chapter=5, title='QUIZ: Rechte, Links & FHS', mtype='QUIZ', xp=130, speaker='ZARA Z3R0', story="Die Permission Matrix öffnet sich zu einem Prüfungsraum.\nZara Z3R0: 'Jede Frage ist eine Tür. Öffne sie, Ghost.\n Zeig mir, dass du die Matrix verstehst.'", why_important='Prüfungsvorbereitung für LPIC-1 Topic 104.5/104.6/104.7.', explanation='Teste dein Wissen über Dateirechte, Links und FHS.', task_description='', expected_commands=[], quiz_questions=[QuizQuestion(question="Was ist 'chmod 4755 /usr/bin/prog'?", options=['A) Sticky Bit + rwxr-xr-x', 'B) SUID + rwxr-xr-x', 'C) SGID + rwxr-xr-x', 'D) Alle Special Bits + rwxr-xr-x'], correct='B', explanation='4755: 4=SUID, 755=rwxr-xr-x. SUID lässt das Programm mit Owner-Rechten laufen.', xp_value=20), QuizQuestion(question='umask ist 022. Welche Rechte hat ein neues Verzeichnis?', options=['A) 644', 'B) 755', 'C) 777', 'D) 700'], correct='B', explanation='Verzeichnis-Basis: 777. 777 - 022 = 755 (rwxr-xr-x).', xp_value=20), QuizQuestion(question='Welcher Unterschied zwischen Hard Link und Symlink?', options=['A) Hard Links können auf Verzeichnisse zeigen, Symlinks nicht', 'B) Symlinks können über Dateisystemgrenzen, Hard Links nicht', 'C) Hard Links sind langsamer', 'D) Symlinks haben dieselbe Inode wie das Original'], correct='B', explanation='Hard Links nur innerhalb desselben Dateisystems (gleiche Inode). Symlinks können überall hin zeigen.', xp_value=20), QuizQuestion(question='find / -perm -2000 sucht Dateien mit welchem gesetzten Bit?', options=['A) SUID', 'B) SGID', 'C) Sticky', 'D) Execute'], correct='B', explanation='2000 = SGID. 4000 = SUID. 1000 = Sticky Bit.', xp_value=20), QuizQuestion(question='Wo liegt lokal selbst installierte Software nach FHS-Standard?', options=['A) /opt', 'B) /usr/local', 'C) /usr/bin', 'D) /srv'], correct='B', explanation='/usr/local für vom Admin selbst installierte Software. /opt für externe Pakete (z.B. Chrome).', xp_value=20), QuizQuestion(question="Was macht 'chown :developers /var/www/html'?", options=["A) Owner auf 'developers' setzen", "B) Group auf 'developers' setzen", "C) Owner und Group auf 'developers' setzen", 'D) Fehler — ungültige Syntax'], correct='B', explanation='chown :gruppe = nur die Gruppe ändern (wie chgrp). chown user:gruppe = beides.', xp_value=20)], exam_tip='Quick Review:\nchmod 4755 = SUID. chmod 2755 = SGID. chmod 1777 = Sticky.\numask: Datei=666-umask, Verzeichnis=777-umask.\nHard Link: selbe Inode, kein Dateisystemübergang.\nSymlink: ln -s, eigene Inode, kann dangling sein.', memory_tip='rwx=421. SUID=4, SGID=2, Sticky=1 vorne. umask subtrahiert von 666/777. Hard Link: gleiche Inode, kein Cross-FS.', gear_reward=None, faction_reward=('Root Collective', 8)), Mission(mission_id='5.BOSS', chapter=5, title='BOSS: Die Permission-Göttin', mtype='BOSS', xp=300, speaker='SYSTEM', story="Die Permission Matrix materialisiert sich zu einer Figur.\n'-rwxr-x--- ' — die Göttin der Zugriffsrechte.\n'Du willst Zugang? Dann beweise dein Recht darauf, Ghost.'\n'chmod, umask, SUID, find — alles oder nichts.'", why_important='Boss-Prüfung: Kapitel 5 Gesamtwissen', explanation='Boss-Kampf: Permission-Göttin — vollständige Prüfung', task_description='Überlebe den Boss-Quiz!', expected_commands=[], ascii_art='\n  ██████╗ ███████╗██████╗ ███╗   ███╗██╗███████╗███████╗██╗ ██████╗ ███╗   ██╗\n  ██╔══██╗██╔════╝██╔══██╗████╗ ████║██║██╔════╝██╔════╝██║██╔═══██╗████╗  ██║\n  ██████╔╝█████╗  ██████╔╝██╔████╔██║██║███████╗███████╗██║██║   ██║██╔██╗ ██║\n  ██╔═══╝ ██╔══╝  ██╔══██╗██║╚██╔╝██║██║╚════██║╚════██║██║██║   ██║██║╚██╗██║\n  ██║     ███████╗██║  ██║██║ ╚═╝ ██║██║███████║███████║██║╚██████╔╝██║ ╚████║\n  ╚═╝     ╚══════╝╚═╝  ╚═╝╚═╝     ╚═╝╚═╝╚══════╝╚══════╝╚═╝ ╚═════╝ ╚═╝  ╚═══╝\n\n  ┌─ ACCESS MATRIX ───────────────────────────────────────────────────┐\n  │  /etc/shadow  :: ----------  (000)  ACCESS: DENIED               │\n  │  /etc/passwd  :: -r--------  (400)  READ:   RESTRICTED           │\n  │  chmod / chown: LOCKED    SUID/SGID: ARMED                       │\n  └───────────────────────────────────────────────────────────────────┘\n\n                    ⚡ CHAOSWERK FACTION :: CHAPTER 5 BOSS ⚡', story_transitions=['PERMISSION-GÖTTIN analysiert deine UIDs. Bereite dich vor.', 'chmod 000 sperrt alles. Sie lacht. Du weißt wie man entsperrt.', 'SUID-Bits leuchten. Wer setzt sie? Wer missbraucht sie?', 'Letzte Frage. rwxrwxrwx oder 000? Die Göttin entscheidet.'], boss_name='PERMISSION-GÖTTIN v5.0', boss_desc='ACCESS MATRIX ONLINE\nCHALLENGER IDENTIFIED: {name} (LVL {level})\n\nYou claim to know permissions?\nThen decode my matrix.\nFail once — you lose access forever.', quiz_questions=[QuizQuestion(question="ls -l zeigt: -rwSr-xr-x — was bedeutet das 'S' (Großbuchstabe)?", options=['A) Sticky Bit + execute gesetzt', 'B) SUID gesetzt, aber execute-Bit FEHLT', 'C) SGID gesetzt und execute gesetzt', 'D) Datei ist ein Socket'], correct='B', explanation="Großes S = SUID gesetzt, aber execute-Bit fehlt. Das ist oft ein Fehler. Kleines 's' = SUID + execute.", xp_value=40), QuizQuestion(question='umask 027. Neue Datei erstellt. Welche Rechte?', options=['A) 750', 'B) 640', 'C) 600', 'D) 644'], correct='B', explanation='Datei-Basis 666 - 027 = 640 (rw-r-----). Verzeichnis wäre 777-027=750.', xp_value=40), QuizQuestion(question='find / -user root -perm -4000 -type f 2>/dev/null — was sucht das?', options=['A) Root-eigene Dateien mit Sticky Bit', 'B) Root-eigene Dateien mit SUID-Bit', 'C) Alle ausführbaren root-Dateien', 'D) Dateien mit vollen Rechten'], correct='B', explanation='-user root = Owner ist root. -perm -4000 = SUID gesetzt. Das sind potenzielle Privilege-Escalation-Targets.', xp_value=40), QuizQuestion(question='chmod g+s /shared — was passiert mit neuen Dateien in /shared?', options=['A) Neue Dateien haben SGID gesetzt', 'B) Neue Dateien erben die Gruppe von /shared', 'C) Neue Dateien gehören root', 'D) Keine Änderung bei neuen Dateien'], correct='B', explanation='SGID auf Verzeichnis: Neue Dateien erben die Gruppe des Verzeichnisses — nützlich für Teamordner.', xp_value=40), QuizQuestion(question="Ghost hat eine Datei mit 'ln original.txt hardlink.txt' erstellt, dann 'rm original.txt'. Zustand?", options=['A) hardlink.txt ist jetzt kaputt (dangling)', 'B) hardlink.txt funktioniert noch — die Daten existieren weiter', 'C) Beide Dateien wurden gelöscht', 'D) rm original.txt schlägt fehl wegen Hard Link'], correct='B', explanation='Hard Links teilen eine Inode. Daten werden erst gelöscht wenn der Link-Count 0 wird. rm original = Link-Count 1→0 erst wenn hardlink.txt auch gelöscht wird.', xp_value=40), QuizQuestion(question="find /var/log -name '*.log' -mtime +30 -exec rm {} \\; — was passiert?", options=['A) Alle .log-Dateien in /var/log werden gelöscht', 'B) .log-Dateien älter als 30 Tage werden gelöscht', 'C) .log-Dateien neuer als 30 Tage werden gelöscht', 'D) Fehler — rm braucht -f'], correct='B', explanation='-mtime +30 = älter als 30 Tage. -exec rm {} \\; führt rm für jede gefundene Datei aus.', xp_value=40)], exam_tip='Boss-Wiederholung: SUID=4, SGID=2, Sticky=1. umask 022 → Dateien 644, Verzeichnisse 755. Hard Link = gleiche Inode. find -perm -4000 = SUID-Check.', memory_tip="Oktale Sonderrechte vorne: chmod 4755=SUID+rwxr-xr-x. ls -l zeigt 's' bei SUID. Sticky Bit auf /tmp zeigt 't'.", gear_reward='regex_scope', faction_reward=('Root Collective', 25))]